from dataclasses import dataclass, field
from typing import Any, Callable

@dataclass
class Tool:
    name: str
    description: str
    fn: Callable[..., Any]
    input_schema: dict

@dataclass
class AgentState:
    messages: list[dict] = field(default_factory=list)
    tool_calls: int = 0
    max_tool_calls: int = 15

def react_agent(task: str, tools: list[Tool], llm_client, max_iterations: int = 15) -> str:
    tool_map = {t.name: t for t in tools}
    state = AgentState(messages=[{"role": "user", "content": task}])

    while state.tool_calls < max_iterations:
        response = llm_client.complete(
            messages=state.messages,
            tools=[{"name": t.name, "description": t.description, "input_schema": t.input_schema} for t in tools],
        )

        if response.stop_reason == "end_turn":
            return response.content[0].text  # final answer

        # Process tool calls
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                tool = tool_map[block.name]
                result = tool.fn(**block.input)
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": str(result)})
                state.tool_calls += 1

        state.messages.append({"role": "assistant", "content": response.content})
        state.messages.append({"role": "user", "content": tool_results})

    raise RuntimeError(f"Agent exceeded {max_iterations} tool calls without finishing")

from dataclasses import dataclass
from enum import Enum

class Domain(Enum):
    CLAIMS = "claims"
    POLICY = "policy"
    FRAUD = "fraud"
    GENERAL = "general"

@dataclass
class RouteDecision:
    domain: Domain
    confidence: float
    fallback: Domain = Domain.GENERAL

def classify_intent(query: str, llm_client) -> RouteDecision:
    prompt = (
        "Classify this insurance query into exactly one category: "
        "claims, policy, fraud, or general. Respond with JSON only: "
        '{"domain": "...", "confidence": 0.0}'
        f"\n\nQuery: {query}"
    )
    response = llm_client.complete(messages=[{"role": "user", "content": prompt}])
    import json
    parsed = json.loads(response.content[0].text)
    return RouteDecision(
        domain=Domain(parsed["domain"]),
        confidence=parsed["confidence"],
    )

def router_agent(query: str, agents: dict[Domain, callable], llm_client) -> str:
    decision = classify_intent(query, llm_client)

    if decision.confidence < 0.6:
        target = decision.fallback
    else:
        target = decision.domain

    specialist = agents.get(target, agents[Domain.GENERAL])
    return specialist(query)

