from dataclasses import dataclass, field
from typing import Optional
import asyncio

@dataclass
class PlanStep:
    step_id: str
    description: str
    tool: str
    inputs: dict
    depends_on: list[str] = field(default_factory=list)
    result: Optional[str] = None

@dataclass
class Plan:
    goal: str
    steps: list[PlanStep]

    def ready_steps(self) -> list[PlanStep]:
        completed_ids = {s.step_id for s in self.steps if s.result is not None}
        return [s for s in self.steps if s.result is None and set(s.depends_on) <= completed_ids]

def create_plan(goal: str, llm_client) -> Plan:
    prompt = (
        f"Create a step-by-step plan to accomplish: {goal}\n"
        "Return JSON: {"steps": [{"step_id": str, "description": str, "
        ""tool": str, "inputs": {}, "depends_on": [step_ids]}]}"
    )
    import json
    response = llm_client.complete(messages=[{"role": "user", "content": prompt}])
    data = json.loads(response.content[0].text)
    return Plan(goal=goal, steps=[PlanStep(**s) for s in data["steps"]])

async def execute_plan(plan: Plan, executors: dict[str, callable]) -> dict[str, str]:
    results: dict[str, str] = {}
    while True:
        ready = plan.ready_steps()
        if not ready:
            break
        tasks = [asyncio.create_task(executors[step.tool](step.inputs)) for step in ready]
        step_results = await asyncio.gather(*tasks, return_exceptions=True)
        for step, result in zip(ready, step_results):
            if isinstance(result, Exception):
                step.result = f"ERROR: {result}"
            else:
                step.result = result
            results[step.step_id] = step.result
    return results
